script.text:
      /* <flatten type="Javascript"> */
function load$EmployeePITInformation$(g) {
  g.add_onRender(on$EmployeePITInformation$Render);
  g.add_onResponseComplete(on$EmployeePITInformation$ResponseComplete);
  g.add_commandEvent(on$EmployeePITInformation$ExecuteCommand);
  g._$k = [];
  g._$i = g._getColumnOrder('stt_rec');
  g._$t = g._getColumnOrder('tag');
  g._$f = 'keys';
}
function scatter$EmployeePITInformation$(g){
  fill$Grid(g, true);
  if (g._rowCount > 0) {
    g._activeRow = g._rowCount;
    g._activeColumn = g._$t;
    g._activeCell = g._getItem(g._activeRow, g._activeColumn);
	}
}
function dispose$EmployeePITInformation$(g) {
  g._$k = g._$i = g._$t = g._$f = null;
  try {g.remove_commandEvent(on$EmployeePITInformation$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$EmployeePITInformation$ResponseComplete);} catch (ex) {}
  try {g.remove_onRender(on$EmployeePITInformation$Render);} catch (ex) {}
}
function on$EmployeePITInformation$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender;
  switch (action) {
    case 'ImportData':
      show$Form(g, 'hrEmployeePITInformationImport');
      break;
    case 'Download':
      request$Download(g, action);
      break;
    case 'OfficalPITInput':
      if (g._official == '0') break;
      if (isCheck$Grid(g)) show$Form(g, 'hrEmployeePITInformationCreate');
        else e.type.cancelEvent = true;
      break;
    default:
      break;
  }
}
function on$EmployeePITInformation$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Download':
      g._key = result[0].Value;
      break;
    default:
      break;
  }
}
function show$Form(g, c) {(!g._denyEdit) ? (g._authorize == 1) ? g.showForm(c) : $message.show($df.getResources(g._language, "Message.NotAccess")) : $message.show(g._denyMessage);}
function on$EmployeePITInformation$Render(sender, eventArgs) {
  var g = eventArgs.grid;
  if (g._hiddenFields) {
    var a = g._hiddenFields, h = '';
    for (var i = 0; i < a.length; i++) {
      setGridHiddenFields(g, a[i].Fields, a[i].Value);
      if (a[i].Value) h += (h == '' ? '' : ',') + a[i].Fields;
    }
    g._externalHiddenFields = h;
  }
}
function setGridHiddenFields(g, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    g._setColumnVisible(g._getColumnOrder($func.trim(a[i])), !v);
  }
}
/* </flatten> */
